import type { ReactElement } from 'react';

import type { FormControlBaseProps } from '../../../../core/types/form-control-props.js';
import type { Timeframe } from '../../../../core/types/time.js';
import { Flex } from '../../../../layouts/flex/Flex.js';
import { Tooltip } from '../../../../overlays/tooltip/Tooltip.js';
import { Text } from '../../../../typography/text/Text.js';
import { useTooltipMessages } from '../../hooks/useTooltipMessages.js';

//#region Typings
interface StepperButtonTooltipProps extends FormControlBaseProps {
  /** Single child of the tooltip considered to trigger the tooltip element. */
  children: ReactElement;
  /** The value of the timeframe selector, containing the 'from' and 'to' timeframe details. */
  value: Timeframe;
  /** String of the value formatted to a display value. */
  formattedStepperValue: string;
}
//#endregion

/**
 * StepperButtonTooltip component to shift the timeframe backward and forward.
 * @internal
 */
export const StepperButtonTooltip = (props: StepperButtonTooltipProps) => {
  const {
    value,
    disabled,
    children,
    formattedStepperValue,
  }: StepperButtonTooltipProps = props;

  const { tooltipFormattedTimeValueStart, tooltipFormattedTimeValueEnd } =
    useTooltipMessages({
      from: value?.from.value ?? '',
      to: value?.to.value ?? '',
    });

  return (
    <Tooltip
      text={
        <Flex flexDirection="column" gap={0}>
          <Text textStyle="small-emphasized">{formattedStepperValue}</Text>
          <Text textStyle="small">{tooltipFormattedTimeValueStart}</Text>
          <Text textStyle="small">{tooltipFormattedTimeValueEnd}</Text>
        </Flex>
      }
      placement="top"
      fallbackPlacements={['top-end', 'bottom', 'bottom-end', 'right', 'left']}
      disabled={disabled}
    >
      {children}
    </Tooltip>
  );
};

(
  StepperButtonTooltip as typeof StepperButtonTooltip & { displayName: string }
).displayName = 'TimeframeStepperTooltip';
